</code></pre> <pre><code>class Solution:
def inorderSuccessor(self, root, p):
    if not root:
        return None
    cur = None
    while root:
        # 根节点小于等于p.val，则找它的右子树，如果右子树为空，则说明没有中序后继节点
        if root.val &lt;= p.val:
            root = root.right
        # 根节点大于p.val，则找它的左子树，一直顺延找下去，才能找到第一个大于p.val的节点，并更新节点
        else:
            cur = root
            root = root.left
    return cur
</code></pre>

DFS <pre><code>class Solution {
    int ans = Integer.MIN_VALUE;

    public int maxPathSum(TreeNode root) {
        dfs(root);
        return ans;
    }

    private int dfs(TreeNode root) {
        if (root == null) return 0;
        // 递归计算左右子节点的最大贡献值
        // 只有在最大贡献值大于 0 时，才会选取对应子节点
        int left = Math.max(dfs(root.left), 0);
        int right = Math.max(dfs(root.right), 0);
        // 节点的最大路径和取决于该节点的值与该节点的左右子节点的最大贡献值
        int path = left + right + root.val;
        ans = Math.max(ans, path);
        // 返回节点的最大贡献值
        return Math.max(left, right) + root.val;
    }
}
</code></pre>

BFSDFS <pre><code>public class Codec {

    // Encodes a tree to a single string.
    public String serialize(TreeNode root) {
        List&lt;String&gt; list = new ArrayList&lt;&gt;();
        Queue&lt;TreeNode&gt; q = new ArrayDeque&lt;&gt;();
        if (root == null) return "";
        q.offer(root);
        list.add(String.valueOf(root.val));
        while (!q.isEmpty()) {
            TreeNode cur = q.poll();
            if (cur.left != null) {
                q.offer(cur.left);
                list.add(String.valueOf(cur.left.val));
            } else list.add("null");
            if (cur.right != null) {
                q.offer(cur.right);
                list.add(String.valueOf(cur.right.val));
            } else list.add("null");
        }
        return String.join(",", list);
    }

    // Decodes your encoded data to tree.
    public TreeNode deserialize(String data) {
        if (data.length() == 0) return null;
        String[] nodes = data.split(",");
        int n = nodes.length;
        Queue&lt;TreeNode&gt; q = new ArrayDeque&lt;&gt;();
        TreeNode root = new TreeNode(Integer.parseInt(nodes[0]));
        q.offer(root);
        int idx = 1;
        while (idx &lt; n) {
            TreeNode cur = q.poll();
            if (!nodes[idx].equals("null")) {
                TreeNode left = new TreeNode(Integer.parseInt(nodes[idx]));
                cur.left = left;
                q.offer(left);
            }
            idx++;
            if (idx &lt; n &amp;&amp; !nodes[idx].equals("null")) {
                TreeNode right = new TreeNode(Integer.parseInt(nodes[idx]));
                cur.right = right;
                q.offer(right);
            }
            idx++;
        }
        return root;
    }
}
</code></pre> <pre><code>public class Codec {

    // Encodes a tree to a single string.
    public String serialize(TreeNode root) {
        if(root == null){
            return "null";
        }
        return root.val + "," + serialize(root.left) + "," + serialize(root.right);
    }

    // Decodes your encoded data to tree.
    public TreeNode deserialize(String data) {
        Queue&lt;String&gt; queue = new ArrayDeque&lt;&gt;(Arrays.asList(data.split(",")));
        return dfs(queue);
    }

    private TreeNode dfs(Queue&lt;String&gt; queue) {
        String val = queue.poll();
        if(val.equals("null")){
            return null;
        }
        TreeNode root = new TreeNode(Integer.parseInt(val));
        root.left = dfs(queue);
        root.right = dfs(queue);
        return root;
    }
}
</code></pre>

滑动窗口 + 有序集合桶排序 <pre><code>class Solution {
    public boolean containsNearbyAlmostDuplicate(int[] nums, int k, int t) {
        int n = nums.length;
        TreeSet&lt;Long&gt; set = new TreeSet&lt;Long&gt;();
        for (int i = 0; i &lt; n; i++) {
            Long floor = set.floor((long) nums[i]);
            Long ceiling = set.ceiling((long) nums[i]);
            if (floor != null &amp;&amp; (long) nums[i] - floor &lt;= (long) t) {
                return true;
            }
            if (ceiling != null &amp;&amp; ceiling - (long) nums[i] &lt;= (long) t) {
                return true;
            }
            set.add((long) nums[i]);
            if (i &gt;= k) {
                set.remove((long) nums[i - k]);
            }
        }
        return false;
    }
}
</code></pre> <pre><code>class Solution {
    public boolean containsNearbyAlmostDuplicate(int[] nums, int k, int t) {
        int n = nums.length;

        //桶的大小为t+1，允许最大元素和最小元素之差为t
        long w = (long) t + 1;

        //因为一个桶有两个元素就会返回true，因此一个桶只有一个元素，可以用哈希表的一条key-value表示桶
        Map&lt;Long, Long&gt; map = new HashMap&lt;Long, Long&gt;();

        for (int i = 0; i &lt; n; i++) {
            long id = getID(nums[i], w);

            //桶里已有元素x，nums[i]和x同属一个桶，值符合范围
            //只保留下标 i 之前的 k 个元素，因此下标也符合范围
            //桶有两个元素就会返回，因此一个桶只有一个元素
            if (map.containsKey(id)) {
                return true;
            }

            //前一个桶有一个元素，并且值的范围符合要求
            if (map.containsKey(id - 1) &amp;&amp; Math.abs(nums[i] - map.get(id - 1)) &lt; w) {
                return true;
            }

            //后一个桶有一个元素，并且值的范围符合要求
            if (map.containsKey(id + 1) &amp;&amp; Math.abs(nums[i] - map.get(id + 1)) &lt; w) {
                return true;
            }

            //没有和nums[i]匹配的元素，把nums[i]加入自己的桶里
            map.put(id, (long) nums[i]);

            //下标范围[i-k+1, i]，从nums[i-k]所在桶移除元素
            if (i &gt;= k) {
                map.remove(getID(nums[i - k], w));
            }
        }
        return false;
    }

    public long getID(long x, long w) {
        //非负数区间，如[0, t] 会被归到 id=0
        //其余的区间，如[(n-1)t+1, nt+1]，每t+1个元素会被归到 id = n-1
        if (x &gt;= 0) {
            return x / w;
        }

        //负数区间，如[-t, -1] 会被归到 id=-1
        //其余的区间，如[-(n+1)t-1, -nt-1]，每t+1个元素会被归到 id = -(n+1)
        return (x + 1) / w - 1;
    }
}
